import React, { useEffect, useRef, useState } from 'react';
import { ArrowRight, ChevronDown, Rocket, ShieldCheck, Zap } from 'lucide-react';
import { HERO_CONTENT, CLIENT_LOGOS } from '../constants';

const Hero: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isBannerHovered, setIsBannerHovered] = useState(false);

  const scrollToSection = (id: string) => {
    const element = document.getElementById(id);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth' });
    }
  };

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let particles: Array<{x: number, y: number, vx: number, vy: number, size: number}> = [];

    const resizeCanvas = () => {
      const parent = canvas.parentElement;
      if (parent) {
        canvas.width = parent.clientWidth;
        canvas.height = parent.clientHeight;
      }
      initParticles();
    };

    const initParticles = () => {
      particles = [];
      const particleCount = Math.min(Math.floor(window.innerWidth / 15), 80);

      for (let i = 0; i < particleCount; i++) {
        particles.push({
          x: Math.random() * canvas.width,
          y: Math.random() * canvas.height,
          vx: (Math.random() - 0.5) * 0.4,
          vy: (Math.random() - 0.5) * 0.4,
          size: Math.random() * 1.5 + 0.5
        });
      }
    };

    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      particles.forEach((p, i) => {
        p.x += p.vx;
        p.y += p.vy;

        if (p.x < 0 || p.x > canvas.width) p.vx *= -1;
        if (p.y < 0 || p.y > canvas.height) p.vy *= -1;

        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(148, 163, 184, 0.3)';
        ctx.fill();

        for (let j = i + 1; j < particles.length; j++) {
          const p2 = particles[j];
          const dx = p.x - p2.x;
          const dy = p.y - p2.y;
          const dist = Math.sqrt(dx * dx + dy * dy);

          if (dist < 120) {
            ctx.beginPath();
            ctx.strokeStyle = `rgba(99, 102, 241, ${0.12 * (1 - dist / 120)})`;
            ctx.lineWidth = 0.8;
            ctx.moveTo(p.x, p.y);
            ctx.lineTo(p2.x, p2.y);
            ctx.stroke();
          }
        }
      });

      animationFrameId = requestAnimationFrame(draw);
    };

    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);
    draw();

    return () => {
      window.removeEventListener('resize', resizeCanvas);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <div className="relative bg-slate-950 overflow-hidden min-h-[95vh] flex items-start justify-center z-0 pt-28 md:pt-36 lg:pt-40">
      {/* Dynamic Background */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden z-0 pointer-events-none">
        <div className="absolute inset-0 bg-grid-pattern opacity-10"></div>
        <div className="absolute -top-[20%] -left-[10%] w-[800px] h-[800px] bg-indigo-900/30 rounded-full blur-[140px] animate-blob mix-blend-screen"></div>
        <div className="absolute -bottom-[10%] -right-[10%] w-[800px] h-[800px] bg-premium-royal/20 rounded-full blur-[140px] animate-blob animation-delay-2000 mix-blend-screen"></div>
        <canvas ref={canvasRef} className="absolute inset-0 w-full h-full z-10" />
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-30 text-center">

        {/* PREMIUM INTERACTIVE BANNER */}
        <div 
          className={`inline-flex items-center transition-all duration-700 ease-in-out cursor-default mb-10 md:mb-12 
            ${isBannerHovered ? 'max-w-4xl px-8 py-4 rounded-2xl bg-slate-900/80 border-premium-gold/40 shadow-[0_0_40px_rgba(251,191,36,0.1)]' : 'max-w-xs px-5 py-1.5 rounded-full bg-indigo-950/40 border-indigo-500/30'}
            border backdrop-blur-xl group animate-fade-in-up`}
          onMouseEnter={() => setIsBannerHovered(true)}
          onMouseLeave={() => setIsBannerHovered(false)}
        >
          {!isBannerHovered ? (
            <div className="flex items-center space-x-3 whitespace-nowrap overflow-hidden">
              <span className="flex h-2.5 w-2.5 rounded-full bg-premium-gold animate-pulse"></span>
              <span className="text-xs md:text-sm font-semibold text-slate-200 uppercase tracking-[0.2em]">
                Product Portfolio Insights
              </span>
              <div className="w-4 h-4 text-slate-500 group-hover:translate-x-1 transition-transform">
                <ChevronDown size={14} />
              </div>
            </div>
          ) : (
            <div className="flex flex-col md:flex-row items-center justify-center space-y-4 md:space-y-0 md:space-x-12 animate-in fade-in zoom-in duration-500">
              <div className="flex items-center space-x-3">
                <Zap className="text-premium-gold h-5 w-5" />
                <div className="text-left">
                  <p className="text-premium-gold font-bold text-lg leading-none">$2M+</p>
                  <p className="text-slate-400 text-[10px] uppercase tracking-wider font-semibold mt-1">Portfolio Value</p>
                </div>
              </div>
              <div className="w-px h-8 bg-slate-700 hidden md:block"></div>
              <div className="flex items-center space-x-3">
                <Rocket className="text-indigo-400 h-5 w-5" />
                <div className="text-left">
                  <p className="text-white font-bold text-lg leading-none">10+</p>
                  <p className="text-slate-400 text-[10px] uppercase tracking-wider font-semibold mt-1">Global Squads</p>
                </div>
              </div>
              <div className="w-px h-8 bg-slate-700 hidden md:block"></div>
              <div className="flex items-center space-x-3">
                <ShieldCheck className="text-emerald-400 h-5 w-5" />
                <div className="text-left">
                  <p className="text-emerald-400 font-bold text-lg leading-none">200+</p>
                  <p className="text-slate-400 text-[10px] uppercase tracking-wider font-semibold mt-1">Sites Managed</p>
                </div>
              </div>
            </div>
          )}

          {/* Shimmer Effect */}
          <div className="absolute inset-0 rounded-[inherit] premium-shimmer opacity-30 animate-shimmer pointer-events-none"></div>
        </div>

        {/* Main Headline */}
        <h1 className="text-4xl md:text-6xl lg:text-7xl font-bold text-white tracking-tight leading-[1.1] mb-8 animate-fade-in-up delay-100">
          I bridge the gap between <br />
          <span className="bg-gradient-to-r from-premium-gold via-amber-400 to-indigo-400 bg-clip-text text-transparent italic font-light">
            complex enterprise operations
          </span> <br />
          and scalable digital products.
        </h1>

        {/* Subheadline */}
        <p className="mt-4 max-w-3xl mx-auto text-lg md:text-xl text-slate-400 font-light leading-relaxed animate-fade-in-up delay-200">
          Delivering multimillion-dollar SaaS and AI solutions for Fortune 500 enterprises 
          through <span className="text-slate-200 font-medium">Agile leadership</span> and 
          <span className="text-slate-200 font-medium"> strategic product delivery</span>.
        </p>

        {/* Action Area */}
        <div className="mt-12 flex flex-col sm:flex-row gap-6 justify-center relative z-20 animate-fade-in-up delay-300">
          <button 
            onClick={() => scrollToSection('work')}
            className="group relative inline-flex items-center justify-center px-10 py-4 font-bold text-white transition-all duration-300 bg-indigo-600 rounded-xl hover:bg-indigo-500 shadow-[0_0_20px_rgba(79,70,229,0.3)] overflow-hidden"
          >
            <span className="relative z-10 flex items-center">
              View Case Studies
              <ArrowRight className="ml-2 h-5 w-5 group-hover:translate-x-1 transition-transform" />
            </span>
            <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000"></div>
          </button>

          <button 
            onClick={() => scrollToSection('contact')}
            className="inline-flex items-center justify-center px-10 py-4 font-bold rounded-xl border-2 border-slate-800 text-slate-300 bg-transparent hover:bg-slate-800/50 hover:text-white transition-all duration-300 backdrop-blur-sm"
          >
            Contact Portfolio
          </button>
        </div>

        {/* Executive Trust Bar */}
        <div className="mt-16 md:mt-24 pt-8 border-t border-slate-800/40 animate-fade-in-up delay-400">
          <p className="text-[10px] md:text-xs text-slate-500 uppercase tracking-[0.3em] font-bold mb-8">Executive Partnerships</p>
          <div className="flex flex-wrap justify-center items-center gap-10 md:gap-20 opacity-50 hover:opacity-100 transition-opacity duration-500">
             {CLIENT_LOGOS.map((client) => (
               <div key={client.name} className="group relative grayscale hover:grayscale-0 transition-all duration-300">
                 <img 
                   src={client.logoUrl} 
                   alt={client.name}
                   className="h-6 md:h-10 w-auto object-contain brightness-0 invert opacity-70 group-hover:opacity-100"
                 />
               </div>
             ))}
          </div>
        </div>
      </div>

      <div className="absolute bottom-8 left-1/2 transform -translate-x-1/2 text-slate-600 animate-pulse-slow hidden md:block pointer-events-none z-30">
        <ChevronDown className="h-8 w-8" />
      </div>
    </div>
  );
};

export default Hero;
